import csv
import re
from datetime import datetime

def parse_salary(salary_str):
    if not salary_str or "not yet confirmed" in salary_str.lower():
        return ""
    # Extract numbers and decimal points
    nums = re.findall(r'\d+(?:,\d+)*', salary_str)
    if nums:
        # Take the first match and remove commas
        return nums[0].replace(',', '')
    return ""

def parse_date(date_str):
    if not date_str:
        return ""

    # Clean up the string
    date_str = re.sub(r'^(Started|start date|Hired|join date|Join date|Hire date|Date started|Joined|Start Date|hired|start):?\s*', '', date_str, flags=re.IGNORECASE).strip()

    # Try various formats
    formats = [
        '%Y-%m-%d',
        '%B %d, %Y',
        '%m-%d-%Y',
        '%Y/%m/%d',
        '%B %Y',
        '%b %d %Y',
        '%b %Y'
    ]

    for fmt in formats:
        try:
            dt = datetime.strptime(date_str, fmt)
            # If only month and year are provided, default to 1st of month
            return dt.strftime('%Y-%m-%d')
        except ValueError:
            continue

    return date_str # Return as is if no format matches

def standardize_dept(dept_str):
    dept_str = dept_str.lower()
    if 'eng' in dept_str:
        return 'Engineering'
    if 'market' in dept_str or 'mktg' in dept_str:
        return 'Marketing'
    if 'human' in dept_str or 'hr' in dept_str:
        return 'Human Resources'
    if 'sales' in dept_str:
        return 'Sales'
    return dept_str.title()

def standardize_status(status_str):
    status_str = status_str.lower()
    if 'active' in status_str:
        return 'Active'
    if 'leave' in status_str:
        return 'On Leave'
    return status_str.title()

def clean_name(name_str):
    # Remove parentheticals like (no relation lol)
    name = re.sub(r'\(.*\)', '', name_str).strip()
    # Handle "Name - Dept" format
    if ' - ' in name:
        name = name.split(' - ')[0].strip()
    # Title case
    return name.title()

def process_records(input_file, output_file):
    with open(input_file, 'r') as f:
        content = f.read()

    # Split by the separator ---
    raw_blocks = content.split('---')

    # Handle the first block which might have headers
    first_block = raw_blocks[0].split('==========================')
    if len(first_block) > 1:
        raw_blocks[0] = first_block[1]

    employees = []

    for block in raw_blocks:
        lines = [l.strip() for l in block.strip().split('\n') if l.strip()]
        if not lines:
            continue

        emp = {
            'Name': '',
            'Department': '',
            'Salary': '',
            'Start Date': '',
            'Status': 'Active' # Default
        }

        # Name is usually the first line
        emp['Name'] = clean_name(lines[0])

        # Check if name line also contains department
        if ' - ' in lines[0] and 'department' in lines[0].lower():
            dept_part = lines[0].split(' - ')[1]
            emp['Department'] = standardize_dept(dept_part)

        for line in lines[1:]:
            lower_line = line.lower()

            if any(x in lower_line for x in ['dept', 'department']):
                emp['Department'] = standardize_dept(line.split(':')[-1].split('-')[-1].strip())
            elif any(x in lower_line for x in ['salary', 'pay', 'compensation', '$']):
                emp['Salary'] = parse_salary(line)
            elif any(x in lower_line for x in ['start', 'hired', 'join', '201', '202']):
                # Check if it looks like a date (contains digits)
                if any(char.isdigit() for char in line):
                    emp['Start Date'] = parse_date(line)
            elif any(x in lower_line for x in ['active', 'leave', 'status']):
                emp['Status'] = standardize_status(line)

        # Fallback for department if not found by keywords
        if not emp['Department']:
            # Check if any line matches known departments
            for line in lines:
                std = standardize_dept(line)
                if std in ['Engineering', 'Marketing', 'Human Resources', 'Sales']:
                    emp['Department'] = std
                    break

        employees.append(emp)

    with open(output_file, 'w', newline='') as f:
        writer = csv.DictWriter(f, fieldnames=['Name', 'Department', 'Salary', 'Start Date', 'Status'])
        writer.writeheader()
        writer.writerows(employees)

if __name__ == "__main__":
    process_records('raw-records.txt', 'employees.csv')

