                'connection_pool': {
                    'size': db.get('pool_size'),
                    'timeout_seconds': db.get('connection_timeout'),
                    'statement_timeout_ms': db.get('statement_timeout'),
                    'idle_timeout_seconds': db.get('idle_timeout')
                },
                'tls': {
                    'mode': db.get('ssl_mode')
                }
            }
            if 'read_replica_host' in db:
                db_mapped['replicas'] = [{'host': db['read_replica_host'], 'role': 'read'}]

            persistence['database'] = db_mapped
            migrated_count += len(db)

        # Cache
        cache = data.get('cache', {})
        if cache:
            cache_mapped = {
                'backend': cache.get('provider'),
                'connection': {
                    'database': cache.get('db_number'),
                    'pool_size': cache.get('max_connections')
                },
                'defaults': {
                    'ttl_seconds': cache.get('ttl_seconds'),
                    'key_prefix': cache.get('key_prefix')
                }
            }
            if 'hosts' in cache:
                cache_mapped['connection']['hosts'] = cache['hosts']
            elif 'host' in cache:
                cache_mapped['connection']['host'] = cache['host']

            if 'port' in cache:
                cache_mapped['connection']['port'] = cache['port']

            persistence['cache'] = cache_mapped
            migrated_count += len(cache)

        if persistence:
            new_config['persistence'] = persistence

        # 3. Observability (Logging)
        log = data.get('logging', {})
        if log:
            obs_log = {
                'level': log.get('level'),
                'format': log.get('format'),
                'sink': {
                    'type': log.get('output')
                },
                'fields': {
                    'timestamp': log.get('include_timestamps'),
                    'request_id': log.get('include_request_id')
                }
            }
            if log.get('log_file'):
                obs_log['sink']['path'] = log.get('log_file')

            if log.get('sentry_dsn'):
                obs_log['error_tracking'] = {'dsn': log.get('sentry_dsn')}

            new_config['observability'] = {'logging': obs_log}
            migrated_count += len(log)

        # 4. Server & Security (API + Features.maintenance_mode)
        api = data.get('api', {})
        features = data.get('features', {})

        server = {
            'base_url': api.get('base_url'),
            'rate_limiting': {
                'requests': api.get('rate_limit'),
                'window_seconds': api.get('rate_limit_window')
            },
            'cors': {
                'allowed_origins': api.get('cors_origins')
            },
            'maintenance_mode': features.get('maintenance_mode')
        }
        new_config['server'] = server

        security = {
            'authentication': {
                'provider': api.get('auth_provider')
            },
            'jwt': {
                'secret_env': api.get('jwt_secret_env'),
                'expiry_minutes': api.get('jwt_expiry_minutes')
            },
            'api_key': {
                'header_name': api.get('api_key_header')
            }
        }
        new_config['security'] = security
        migrated_count += len(api)

        # 5. Features
        feat_mapped = {
            'websockets': features.get('enable_websockets'),
            'graphql': features.get('enable_graphql'),
            'batch_processing': features.get('enable_batch_processing')
        }
        new_config['features'] = feat_mapped

        if features.get('debug_toolbar'):
            report_data['warnings'].append(f"`debug_toolbar` was dropped (was `true` in {env_name})")

        migrated_count += 4 # websockets, graphql, batch, maintenance

        # 6. Storage
        st = data.get('storage', {})
        if st:
            st_mapped = {
                'backend': st.get('provider'),
                'limits': {
                    'max_file_size_mb': st.get('max_file_size_mb'),
                    'allowed_extensions': st.get('allowed_extensions')
                }
            }
            if st.get('provider') == 'local':
                st_mapped['local'] = {'path': st.get('local_path')}
            elif st.get('provider') == 's3':
                st_mapped['s3'] = {
                    'bucket': st.get('s3_bucket'),
                    'region': st.get('s3_region')
                }

            if st.get('cdn_url'):
                st_mapped['cdn'] = {'base_url': st.get('cdn_url')}

            new_config['storage'] = st_mapped
            migrated_count += len(st)

        # Write YAML
        output_path = f'config/{env_name}.yaml'
        with open(output_path, 'w') as f:
            f.write("# Migrated from legacy JSON config\n")
            yaml.dump(new_config, f, sort_keys=False, default_flow_style=False)

        env_notes = ""
        if 'read_replica_host' in db:
            env_notes = "production has read replicas"

        report_data['environments'].append({
            'name': env_name,
            'path': output_path,
            'count': migrated_count,
            'notes': env_notes
        })

    # Add general warnings
    report_data['warnings'].append("Password environment variables should be verified")

    # Generate Report
    with open('migration-report.md', 'w') as f:
        f.write("# Configuration Migration Report\n\n")
        f.write(f"Migrated {len(report_data['environments'])} environments. ")
        f.write(f"Config version change: {old_version} -> 3.0\n\n")

        for env in report_data['environments']:
            f.write(f"## Environment: {env['name']}\n")
            f.write(f"- **Output file**: `{env['path']}`\n")
            f.write(f"- **Settings migrated**: {env['count']}\n")
            if env['notes']:
                f.write(f"- **Notes**: {env['notes']}\n")
            f.write("\n")

        f.write("## Deprecated Settings Dropped\n\n")
        f.write("| Setting | Old Value | Reason |\n")
        f.write("|---------|-----------|--------|\n")
        for dep in report_data['deprecated_dropped']:
            f.write(f"| `{dep['key']}` | `{dep['value']}` | {dep['reason']} |\n")
        f.write("\n")

        f.write("## Warnings\n\n")
        for warn in report_data['warnings']:
            f.write(f"- {warn}\n")

if __name__ == "__main__":
    migrate()
